// lift(sel)(pred)(entity) = pred(sel(entity))
// — a generic 3-level HOF with ZERO type annotations.
//
// GCP propagates constraints BACKWARD through the chain:
//   1. is_passing  needs  n.points    → sel result must have { points: Int }
//   2. get_score   returns player.test → player.test must have { points: Int }
//   3. alice.test = { score=85, gpa=3.5 } — no 'points' field!
//
// Backward constraint propagation reports the error at the entity definition
// where the incompatible structure is first constructed.
//
// No other type system catches this without EXPLICIT type annotations on lift.

let lift = sel -> pred -> entity -> pred(sel(entity));

let get_score  = player -> player.test;
let is_passing = n -> n.points >= 60;   // needs n.points : Int
let is_ace     = n -> n.score  >= 90;   // needs n.score  : Int

let check_pass = lift(get_score)(is_passing);
let check_ace  = lift(get_score)(is_ace);

// alice.test has { score, gpa } but NOT { points }
// ← ERROR reported here: backward constraint from is_passing reaches alice
let alice = {name = "Alice", test = {score = 85, gpa = 3.5}, rank = 3};

let pass = check_pass(alice);
let ace  = check_ace(alice);    // ✓  score exists

(pass, ace)

// Both functions work on the same `emp` entity but access DIFFERENT fields.
// Neither function alone determines the full type.
// GCP merges their constraints: emp : { salary: Int, years: Int }
//
// TypeScript: (emp: { salary: number; years: number }) => ... — must declare
// Haskell:    data Emp = Emp { salary :: Int, years :: Int }  — must declare
// GCP:        zero declarations — structural type emerges from usage.

let gross     = emp -> emp.salary * 12;  // constrains emp.salary : Int
let is_senior = emp -> emp.years >= 10;  // constrains emp.years  : Int

// Extra fields (name, dept) pass through — structural subtyping
let alice = {salary = 5000, years = 12, name = "Alice"};
let bob   = {salary = 4000, years = 5,  name = "Bob"};

let earn_alice = gross(alice);       // 60000
let earn_bob   = gross(bob);         // 48000
let senior     = is_senior(alice);   // true

earn_alice;

// `ticket` type is NEVER declared.
// GCP infers it from all access patterns across both functions:
//   urgency_score reads ticket.priority → Priority (ADT)
//   is_urgent     reads ticket.deadline → Int
// → ticket : { priority: Priority, deadline: Int }
//
// TypeScript: interface Ticket { priority: Priority; deadline: number }
// Haskell:    data Ticket = Ticket { priority :: Priority, deadline :: Int }

outline Priority = Low | Medium | High;

let urgency_score = pri -> days ->
    match pri {
        High   -> 3 > days,
        Medium -> 7 > days,
        _      -> false
    };

let is_urgent = ticket -> urgency_score(ticket.priority)(ticket.deadline);

let t1 = {priority = High,   deadline = 2,  owner = "Alice"};
let t2 = {priority = Medium, deadline = 10, owner = "Bob"};
let t3 = {priority = Low,    deadline = 1,  owner = "Carol"};

is_urgent(t1);   // → true   (High, 2 days left)

// outline Product has:
//   id, price   → REQUIRED — must be provided at construction
//   category    → DEFAULT VALUE ("general") — auto-fills, overridable
//   sku         → LITERAL TYPE (#"AUTO")   — always "AUTO", immutable

outline Product = {
    id:       String,
    price:    Int,
    category: "general",   // default-value field
    sku:      #"AUTO"      // literal-type field
};

// ✓ Only required fields — defaults fill automatically
let p1 = Product{id = "P001", price = 99};
// p1.category → "general"  (default applied)
// p1.sku      → "AUTO"     (literal type filled)

// ✓ Override the default category
let p2 = Product{id = "P002", price = 149, category = "premium"};

// ✗ ERROR: 'price' is required but not provided
let p3 = Product{id = "P003"};

p1.sku;   // → "AUTO"

// Entity literal type: a field whose type IS a specific entity constant.
// The constant is always auto-filled — callers cannot override it.

outline Service = {
    name: String,
    meta: #{ env = "prod", version = 1 }   // entity literal — always this exact record
};

// Only `name` needs to be supplied — `meta` is auto-filled from the literal
let svc = Service{name = "auth-service"};

// Trying to override meta at construction is a compile-time error:
//   let bad = Service{name = "x", meta = {env = "dev", version = 2}};  // ← NOT_ASSIGNABLE

svc.meta.env;   // → "prod"

// Tuple literal type: a field whose type IS a specific tuple constant.
// Works identically to string literal types — auto-filled, immutable.

outline Origin = {
    label:  String,
    coords: #(0, 0)   // tuple literal — always (0, 0)
};

outline VersionedApi = {
    name:    String,
    version: #(1, 0, 0)   // semantic version — always 1.0.0
};

let o   = Origin{label = "centre"};
let api = VersionedApi{name = "gateway"};

// Trying to supply coords=(1,2) is a compile-time error (NOT_ASSIGNABLE)
// let bad = Origin{label = "p", coords = (1, 2)};

(o.label, o.coords, api.version)

// External builders: __name__<OutlineType>{overrides}
//
// GCP checks the type at compile time — the outline constrains valid fields.
// At runtime, a registered plugin fills in the values.
//
// This lets the same GCP code work against different backends
// (memory, database, HTTP, etc.) by swapping only the registered plugin.

outline Profile = {
    id:     String,
    name:   String,
    role:   #"user"    // literal-type — always "user", auto-filled
};

let p = __external_builder__<Profile>{id = "u001", name = "Alice"};

let pname = p.name;   // → "Alice"
let prole = p.role;   // → "user"  (literal type auto-filled)

(pname, prole)

// Outline field defaults support Long literals and negative numbers:
//
//   count:  0L    → Long literal default
//   offset: -1    → negative Int default
//   delta:  -1L   → negative Long default

outline Counter = {
    name:   String,
    count:  0L,   // Long literal default
    offset: -1,   // negative Int default
    delta:  -1L   // negative Long default
};

let c = Counter{name = "hits"};

// c.count  → 0   (Long default)
// c.offset → -1  (negative Int default)
// c.delta  → -1  (negative Long default)

(c.count, c.offset, c.delta)

// Poly (product of roles): 10 & "Will" & {name="Bob"}
// This single value IS all three at once.
//
// Role-based dispatch: each function receives only its relevant component.
// No casting, no interfaces, no wrapper types needed.
//
// TypeScript: requires union types + explicit narrowing
// Haskell:    requires type classes + instances
// GCP:        poly + typed parameters = automatic role extraction

let value = 10 & "Will" & {name = "Bob"};

let f_ent = (value:{name:String}) -> value.name;
let f_int = (value:Int)           -> value + 1;
let f_str = (value:String)        -> value + "!";

let r1 = f_ent(value);   // → "Bob"
let r2 = f_int(value);   // → 11
let r3 = f_str(value);   // → "Will!"

(r1, r2, r3)
